      "id": "2032",
      "name": "OkCredit",
      "slug": "okcredit",
      "year": 2018,
      "batch": "Summer 2018",
      "wave": "wave-2015-2018",
      "waveLabel": "2015-2018",
      "waveName": "Neobanks, cards, global fintech",
